/**
 * import-schedule-ocr — Edge Function
 *
 * Required secrets (Supabase Dashboard → Edge Functions → Secrets, or `supabase secrets set`):
 *   SUPABASE_URL
 *   SUPABASE_SERVICE_ROLE_KEY
 *   GOOGLE_CLOUD_CLIENT_EMAIL   (GCP service account)
 *   GOOGLE_CLOUD_PRIVATE_KEY    (PEM, newlines as \n in env)
 *
 * Deploy: `supabase functions deploy import-schedule-ocr`
 * GCP: enable "Cloud Vision API" for the service account project.
 *
 * Client calls: supabase.functions.invoke('import-schedule-ocr', { body: { batch_id } })
 */
// @ts-expect-error Deno std
import { serve } from 'https://deno.land/std@0.168.0/http/server.ts';
// @ts-expect-error Deno esm
import { createClient } from 'https://esm.sh/@supabase/supabase-js@2';
import { extractPdfText, visionDocumentTextFromImage } from './extract.ts';
import { parseScheduleText } from './parser.ts';

const corsHeaders: Record<string, string> = {
  'Access-Control-Allow-Origin': '*',
  'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
};

type Body = { batch_id?: string };

function extMime(path: string): 'image' | 'pdf' | 'unknown' {
  const p = path.toLowerCase();
  if (p.endsWith('.pdf')) return 'pdf';
  if (p.endsWith('.png') || p.endsWith('.jpg') || p.endsWith('.jpeg') || p.endsWith('.heic') || p.endsWith('.webp')) {
    return 'image';
  }
  return 'unknown';
}

serve(async (req) => {
  if (req.method === 'OPTIONS') {
    return new Response('ok', { headers: corsHeaders });
  }

  const supabaseUrl = Deno.env.get('SUPABASE_URL');
  const serviceKey = Deno.env.get('SUPABASE_SERVICE_ROLE_KEY');
  if (!supabaseUrl || !serviceKey) {
    return new Response(JSON.stringify({ error: 'Server misconfigured' }), {
      status: 500,
      headers: { ...corsHeaders, 'Content-Type': 'application/json' },
    });
  }

  const authHeader = req.headers.get('Authorization');
  if (!authHeader?.startsWith('Bearer ')) {
    return new Response(JSON.stringify({ error: 'Unauthorized' }), {
      status: 401,
      headers: { ...corsHeaders, 'Content-Type': 'application/json' },
    });
  }

  const jwt = authHeader.replace('Bearer ', '');
  const supabase = createClient(supabaseUrl, serviceKey);
  const { data: userData, error: userErr } = await supabase.auth.getUser(jwt);
  if (userErr || !userData.user) {
    return new Response(JSON.stringify({ error: 'Invalid session' }), {
      status: 401,
      headers: { ...corsHeaders, 'Content-Type': 'application/json' },
    });
  }
  const userId = userData.user.id;

  let body: Body;
  try {
    body = (await req.json()) as Body;
  } catch {
    return new Response(JSON.stringify({ error: 'Invalid JSON' }), {
      status: 400,
      headers: { ...corsHeaders, 'Content-Type': 'application/json' },
    });
  }

  const batchId = body.batch_id;
  if (!batchId || typeof batchId !== 'string') {
    return new Response(JSON.stringify({ error: 'batch_id required' }), {
      status: 400,
      headers: { ...corsHeaders, 'Content-Type': 'application/json' },
    });
  }

  const { data: batch, error: batchErr } = await supabase
    .from('schedule_import_batches')
    .select('id,user_id,month_key,source_type,source_file_path')
    .eq('id', batchId)
    .maybeSingle();

  if (batchErr || !batch || batch.user_id !== userId) {
    return new Response(JSON.stringify({ error: 'Batch not found' }), {
      status: 404,
      headers: { ...corsHeaders, 'Content-Type': 'application/json' },
    });
  }

  const filePath = batch.source_file_path as string | null;
  if (!filePath) {
    return new Response(JSON.stringify({ error: 'Batch has no file path' }), {
      status: 400,
      headers: { ...corsHeaders, 'Content-Type': 'application/json' },
    });
  }

  const segments = filePath.split('/').filter(Boolean);
  if (segments[0] !== userId) {
    return new Response(JSON.stringify({ error: 'Invalid storage path' }), {
      status: 403,
      headers: { ...corsHeaders, 'Content-Type': 'application/json' },
    });
  }

  await supabase
    .from('schedule_import_batches')
    .update({ parse_status: 'extracting', parse_error: null, updated_at: new Date().toISOString() })
    .eq('id', batchId);

  const { data: fileBlob, error: dlErr } = await supabase.storage.from('schedule-imports').download(filePath);
  if (dlErr || !fileBlob) {
    await supabase
      .from('schedule_import_batches')
      .update({
        parse_status: 'failed',
        parse_error: dlErr?.message ?? 'Download failed',
        updated_at: new Date().toISOString(),
      })
      .eq('id', batchId);
    return new Response(JSON.stringify({ error: 'Could not download file', details: dlErr?.message }), {
      status: 500,
      headers: { ...corsHeaders, 'Content-Type': 'application/json' },
    });
  }

  const buf = new Uint8Array(await fileBlob.arrayBuffer());
  const kind = extMime(filePath);

  let rawText = '';
  let pdfWeak = false;

  try {
    if (kind === 'image' || kind === 'unknown') {
      rawText = await visionDocumentTextFromImage(buf);
      if (kind === 'unknown' && rawText.trim().length < 20) {
        // Try PDF extraction if extensionless file is actually PDF
        const pdfTry = await extractPdfText(buf);
        if (pdfTry.text.trim().length > rawText.trim().length) {
          rawText = pdfTry.text;
          pdfWeak = pdfTry.usedOcrFallback;
        }
      }
    } else if (kind === 'pdf') {
      const pdfTry = await extractPdfText(buf);
      rawText = pdfTry.text;
      pdfWeak = pdfTry.usedOcrFallback;
      if (pdfWeak) {
        rawText += '\n\n[import: PDF text extraction was weak; scanned PDFs may need a photo/screenshot import.]';
      }
    } else {
      rawText = await visionDocumentTextFromImage(buf);
    }
  } catch (e) {
    const msg = e instanceof Error ? e.message : String(e);
    await supabase
      .from('schedule_import_batches')
      .update({
        parse_status: 'failed',
        parse_error: msg,
        updated_at: new Date().toISOString(),
      })
      .eq('id', batchId);
    return new Response(JSON.stringify({ error: 'Extraction failed', details: msg }), {
      status: 500,
      headers: { ...corsHeaders, 'Content-Type': 'application/json' },
    });
  }

  const monthKey =
    (batch.month_key as string | null) ||
    new Date().toISOString().slice(0, 7);

  const parsed = parseScheduleText(rawText, monthKey);

  await supabase.from('schedule_import_candidates').delete().eq('batch_id', batchId);

  const rows = parsed.map((p) => ({
    batch_id: batchId,
    date: p.date,
    day_of_week: p.day_of_week,
    pairing_code: p.pairing_code,
    report_time: p.report_time,
    city: p.city,
    d_end_time: p.d_end_time,
    layover: p.layover,
    wx: p.wx,
    status_code: p.status_code,
    notes: p.notes,
    confidence_score: p.confidence_score,
    warning_flag: p.warning_flag || pdfWeak,
    raw_row_text: p.raw_row_text,
  }));

  const { error: insErr } =
    rows.length === 0
      ? { error: null as null }
      : await supabase.from('schedule_import_candidates').insert(rows);
  if (insErr) {
    await supabase
      .from('schedule_import_batches')
      .update({
        parse_status: 'failed',
        parse_error: insErr.message,
        raw_extracted_text: rawText.slice(0, 50000),
        updated_at: new Date().toISOString(),
      })
      .eq('id', batchId);
    return new Response(JSON.stringify({ error: 'Could not save candidates', details: insErr.message }), {
      status: 500,
      headers: { ...corsHeaders, 'Content-Type': 'application/json' },
    });
  }

  const warningCount = rows.filter((r) => r.warning_flag).length;

  await supabase
    .from('schedule_import_batches')
    .update({
      raw_extracted_text: rawText.slice(0, 50000),
      parse_status: 'parsed',
      row_count: rows.length,
      warning_count: warningCount,
      parse_error: pdfWeak ? 'PDF text may be incomplete (scanned document).' : null,
      updated_at: new Date().toISOString(),
    })
    .eq('id', batchId);

  return new Response(
    JSON.stringify({
      ok: true,
      batch_id: batchId,
      row_count: rows.length,
      warning_count: warningCount,
      pdf_weak: pdfWeak,
    }),
    { headers: { ...corsHeaders, 'Content-Type': 'application/json' } }
  );
});

/**
 * Text extraction: Google Vision (images) + pdf.js (PDF text; weak text → flag for OCR upgrade path).
 */

import { encode as encodeBase64 } from 'https://deno.land/std@0.168.0/encoding/base64.ts';
import { SignJWT, importPKCS8 } from 'npm:jose@5';
import { getDocument, GlobalWorkerOptions } from 'npm:pdfjs-dist/legacy/build/pdf.mjs';

// pdf.js in Edge: avoid worker fetch
GlobalWorkerOptions.workerSrc = '';

const VISION_SCOPE = 'https://www.googleapis.com/auth/cloud-vision';

let cachedToken: { token: string; exp: number } | null = null;

async function getGoogleAccessToken(): Promise<string> {
  const now = Math.floor(Date.now() / 1000);
  if (cachedToken && cachedToken.exp > now + 60) return cachedToken.token;

  const clientEmail = Deno.env.get('GOOGLE_CLOUD_CLIENT_EMAIL');
  const privateKeyRaw = Deno.env.get('GOOGLE_CLOUD_PRIVATE_KEY');
  if (!clientEmail || !privateKeyRaw) {
    throw new Error('Missing GOOGLE_CLOUD_CLIENT_EMAIL or GOOGLE_CLOUD_PRIVATE_KEY');
  }
  const privateKey = privateKeyRaw.replace(/\\n/g, '\n');
  const key = await importPKCS8(privateKey, 'RS256');

  const jwt = await new SignJWT({ scope: VISION_SCOPE })
    .setProtectedHeader({ alg: 'RS256' })
    .setIssuer(clientEmail)
    .setSubject(clientEmail)
    .setAudience('https://oauth2.googleapis.com/token')
    .setIssuedAt(now)
    .setExpirationTime(now + 3600)
    .sign(key);

  const res = await fetch('https://oauth2.googleapis.com/token', {
    method: 'POST',
    headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
    body: new URLSearchParams({
      grant_type: 'urn:ietf:params:oauth:grant-type:jwt-bearer',
      assertion: jwt,
    }),
  });
  const data = await res.json();
  if (!res.ok) {
    throw new Error(`Google OAuth failed: ${JSON.stringify(data)}`);
  }
  const accessToken = data.access_token as string;
  cachedToken = { token: accessToken, exp: now + 3500 };
  return accessToken;
}

export async function visionDocumentTextFromImage(bytes: Uint8Array): Promise<string> {
  const accessToken = await getGoogleAccessToken();
  const b64 = encodeBase64(bytes);

  const res = await fetch('https://vision.googleapis.com/v1/images:annotate', {
    method: 'POST',
    headers: {
      Authorization: `Bearer ${accessToken}`,
      'Content-Type': 'application/json',
    },
    body: JSON.stringify({
      requests: [
        {
          image: { content: b64 },
          features: [{ type: 'DOCUMENT_TEXT_DETECTION', maxResults: 50 }],
        },
      ],
    }),
  });

  const json = await res.json();
  if (!res.ok) {
    throw new Error(`Vision API error: ${JSON.stringify(json)}`);
  }

  const resp = json.responses?.[0];
  const full = resp?.fullTextAnnotation?.text;
  if (typeof full === 'string' && full.trim().length > 0) return full;

  const text0 = resp?.textAnnotations?.[0]?.description;
  if (typeof text0 === 'string') return text0;

  return '';
}

const MIN_PDF_TEXT_CHARS = 80;

export async function extractPdfText(bytes: Uint8Array): Promise<{ text: string; usedOcrFallback: boolean }> {
  const buf = bytes.buffer.slice(bytes.byteOffset, bytes.byteOffset + bytes.byteLength);
  const loadingTask = getDocument({
    data: buf,
    disableWorker: true,
    useSystemFonts: true,
  });
  const pdf = await loadingTask.promise;
  const parts: string[] = [];
  for (let p = 1; p <= pdf.numPages; p++) {
    const page = await pdf.getPage(p);
    const content = await page.getTextContent();
    const line = content.items
      .map((it: { str?: string }) => (typeof it.str === 'string' ? it.str : ''))
      .join(' ');
    if (line.trim()) parts.push(line);
  }
  const text = parts.join('\n');
  const weak = text.trim().length < MIN_PDF_TEXT_CHARS;
  return { text, usedOcrFallback: weak };
}

/**
 * OCR schedule text → candidate rows (modular heuristics for airline roster layouts).
 */

export type ParsedCandidate = {
  date: string | null;
  day_of_week: string | null;
  pairing_code: string | null;
  report_time: string | null;
  city: string | null;
  d_end_time: string | null;
  layover: string | null;
  wx: string | null;
  status_code: string | null;
  notes: string | null;
  confidence_score: number;
  warning_flag: boolean;
  raw_row_text: string;
};

const DOW = ['SU', 'MO', 'TU', 'WE', 'TH', 'FR', 'SA'];

function pad2(n: number): string {
  return String(n).padStart(2, '0');
}

/** Infer YYYY-MM-DD from line text using month_hint "YYYY-MM". */
export function inferIsoDateFromLine(line: string, monthHint: string): string | null {
  const ym = /^(\d{4})-(\d{2})$/.exec(monthHint.trim());
  if (!ym) return null;
  const y = Number(ym[1]);
  const m = Number(ym[2]);

  // 3/24, 03/24, 3-24
  let mre = /\b(\d{1,2})[\/\-](\d{1,2})\b/.exec(line);
  if (mre) {
    const a = Number(mre[1]);
    const b = Number(mre[2]);
    let month = a;
    let day = b;
    if (a > 12) {
      day = a;
      month = b;
    }
    if (month >= 1 && month <= 12 && day >= 1 && day <= 31) {
      return `${y}-${pad2(month)}-${pad2(day)}`;
    }
  }

  // Mar 24, MAR 24
  const monNames = ['jan', 'feb', 'mar', 'apr', 'may', 'jun', 'jul', 'aug', 'sep', 'oct', 'nov', 'dec'];
  const monRe = new RegExp(`\\b(${monNames.join('|')})\\.?\\s+(\\d{1,2})\\b`, 'i');
  const mr = monRe.exec(line.toLowerCase());
  if (mr) {
    const mi = monNames.indexOf(mr[1].slice(0, 3));
    const d = Number(mr[2]);
    if (mi >= 0 && d >= 1 && d <= 31) {
      return `${y}-${pad2(mi + 1)}-${pad2(d)}`;
    }
  }

  return null;
}

function normalizeTime(t: string): string {
  const s = t.trim();
  const m = /^(\d{1,2}):(\d{2})\s*(AM|PM)?$/i.exec(s);
  if (m) {
    let h = Number(m[1]);
    const min = m[2];
    const ap = m[3]?.toUpperCase();
    if (ap === 'PM' && h < 12) h += 12;
    if (ap === 'AM' && h === 12) h = 0;
    return `${String(h).padStart(2, '0')}${min}`;
  }
  const four = /^(\d{3,4})$/.exec(s.replace(/\s/g, ''));
  if (four) {
    const n = four[1].padStart(4, '0');
    return `${n.slice(0, 2)}${n.slice(2)}`;
  }
  return s;
}

/** Main parse: lines → candidates; uses month_hint for dates. */
export function parseScheduleText(raw: string, monthHint: string): ParsedCandidate[] {
  const lines = raw
    .split(/\r?\n/)
    .map((l) => l.replace(/\s+/g, ' ').trim())
    .filter((l) => l.length > 0);

  const out: ParsedCandidate[] = [];
  let lastDate: string | null = null;

  for (const rawLine of lines) {
    const line = rawLine.trim();
    if (!line) continue;

    const iso = inferIsoDateFromLine(line, monthHint);
    if (iso) lastDate = iso;

    const row = classifyLine(line, monthHint, lastDate);
    out.push(row);

    if (row.date) lastDate = row.date;
  }

  return out;
}

function classifyLine(line: string, monthHint: string, lastDate: string | null): ParsedCandidate {
  const upper = line.toUpperCase();
  const iso = inferIsoDateFromLine(line, monthHint) ?? lastDate;

  const base = {
    date: iso,
    day_of_week: iso ? dayOfWeekFromIso(iso) : null,
    pairing_code: null as string | null,
    report_time: null as string | null,
    city: null as string | null,
    d_end_time: null as string | null,
    layover: null as string | null,
    wx: null as string | null,
    status_code: null as string | null,
    notes: null as string | null,
    confidence_score: 0.55,
    warning_flag: false,
    raw_row_text: line,
  };

  // Standalone duty codes
  if (/^\s*OFF\s*$/i.test(line)) {
    return { ...base, pairing_code: '—', status_code: 'OFF', confidence_score: 0.95 };
  }
  if (/^\s*PTO\s*$/i.test(line)) {
    return { ...base, pairing_code: '—', status_code: 'PTO', confidence_score: 0.95 };
  }
  if (/^\s*CONT\s*$/i.test(line)) {
    return { ...base, pairing_code: 'CONT', status_code: 'CONT', confidence_score: 0.85 };
  }

  // Reserve: RSV1 JFK, RSV 2 LAX
  const rsv = /^(RSV\d?)\s+([A-Z]{3})\s*$/i.exec(line);
  if (rsv) {
    return {
      ...base,
      pairing_code: rsv[1].toUpperCase(),
      city: rsv[2].toUpperCase(),
      status_code: 'RSV',
      confidence_score: 0.88,
    };
  }

  // Deadhead: DH 0530 BOS 0805 JFK
  const dh = /^DH\s+(\d{3,4})\s+([A-Z]{3})\s+(\d{3,4})\s+([A-Z]{3})\s*$/i.exec(line.replace(/\s+/g, ' '));
  if (dh) {
    return {
      ...base,
      pairing_code: 'DH',
      report_time: normalizeTime(dh[1]),
      city: `${dh[2].toUpperCase()}→${dh[4].toUpperCase()}`,
      d_end_time: normalizeTime(dh[3]),
      status_code: 'DH',
      confidence_score: 0.82,
    };
  }

  // Trip-like: J3409 0800 JFK 1430 SFO  (pairing + times + airports)
  const trip = /^([A-Z]?\d{3,5}[A-Z]?)\s+(\d{3,4})\s+([A-Z]{3})\s+(\d{3,4})\s+([A-Z]{3})\b/i.exec(
    line.replace(/\s+/g, ' ')
  );
  if (trip) {
    return {
      ...base,
      pairing_code: trip[1].toUpperCase(),
      report_time: normalizeTime(trip[2]),
      city: `${trip[3].toUpperCase()}→${trip[5].toUpperCase()}`,
      d_end_time: normalizeTime(trip[4]),
      status_code: 'TRIP',
      confidence_score: 0.8,
    };
  }

  // Shorter trip fragment: J3409 0800 JFK
  const shortTrip = /^([A-Z]?\d{3,5}[A-Z]?)\s+(\d{3,4})\s+([A-Z]{3})\b/i.exec(line);
  if (shortTrip) {
    return {
      ...base,
      pairing_code: shortTrip[1].toUpperCase(),
      report_time: normalizeTime(shortTrip[2]),
      city: shortTrip[3].toUpperCase(),
      status_code: 'TRIP',
      confidence_score: 0.65,
      warning_flag: true,
    };
  }

  // Blank / noise
  if (line.length < 2 || /^[\-_.]+$/.test(line)) {
    return {
      ...base,
      status_code: 'BLANK',
      confidence_score: 0.2,
      warning_flag: true,
    };
  }

  // Keyword in line
  if (/\bOFF\b/i.test(line)) {
    return { ...base, status_code: 'OFF', pairing_code: '—', confidence_score: 0.7 };
  }
  if (/\bPTO\b/i.test(line)) {
    return { ...base, status_code: 'PTO', pairing_code: '—', confidence_score: 0.7 };
  }
  if (/\bCONT\b/i.test(line)) {
    return { ...base, status_code: 'CONT', pairing_code: 'CONT', confidence_score: 0.65 };
  }
  if (/\bRSV\b/i.test(line)) {
    return { ...base, status_code: 'RSV', pairing_code: 'RSV', confidence_score: 0.6, warning_flag: true };
  }
  if (/\bDH\b/i.test(line)) {
    return { ...base, status_code: 'DH', confidence_score: 0.55, warning_flag: true };
  }

  return {
    ...base,
    notes: upper.slice(0, 200),
    status_code: 'UNK',
    confidence_score: 0.35,
    warning_flag: true,
  };
}

function dayOfWeekFromIso(iso: string): string | null {
  const p = iso.split('-').map(Number);
  if (p.length !== 3) return null;
  const d = new Date(p[0], p[1] - 1, p[2]);
  if (Number.isNaN(d.getTime())) return null;
  return DOW[d.getDay()] ?? null;
}
